/* Root design tokens */
:root {
  --color-bg: #000000;
  --color-bg-elevated: #121212;
  --color-bg-soft: #1B1B1F;

  --color-primary: #1B1B1F;
  --color-primary-strong: #000000;

  --color-secondary-cyan: #2AD1FF;
  --color-secondary-yellow: #FFD857;
  --color-secondary-green: #6AF15B;
  --color-secondary-purple: #5A2D7D;

  --color-accent-red: #FF3B3B;
  --color-accent-lime: #9FE22A;

  --color-border-subtle: #303030;

  --color-text-main: #F5F5F5;
  --color-text-muted: #B3B3B3;

  --font-heading: 'Black Ops One', Impact, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-body: 'Work Sans', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;

  --font-size-h1: 44px;
  --font-size-h2: 32px;
  --font-size-h3: 24px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  --shadow-neon-cyan: 0 0 18px rgba(42, 209, 255, 0.85);
  --shadow-neon-lime: 0 0 18px rgba(159, 226, 42, 0.9);

  --header-height: 72px;
  --footer-bg-gradient: linear-gradient(to top, #000000 0%, #121212 40%, #1B1B1F 100%);
}

/* Reset / base */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  min-height: 100vh;
  background-color: var(--color-bg);
  color: var(--color-text-main);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover {
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-secondary-cyan);
  outline-offset: 2px;
}

/* Layout utilities */

.page-content {
  min-height: 60vh;
  background-color: var(--color-bg);
}

/* Skip link */

.skip-link {
  position: absolute;
  left: -999px;
  top: auto;
  width: 1px;
  height: 1px;
  overflow: hidden;
  padding: var(--space-1) var(--space-2);
  background-color: var(--color-secondary-cyan);
  color: #000000;
  z-index: 2000;
}

.skip-link:focus {
  left: var(--space-2);
  top: var(--space-2);
  width: auto;
  height: auto;
}

/* Header */

.site-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  background: radial-gradient(circle at top left, rgba(42, 209, 255, 0.35) 0, rgba(0, 0, 0, 0.98) 55%), #000000;
  border-bottom: 1px solid rgba(48, 48, 48, 0.9);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.9);
}

.header-inner {
  max-width: 1200px;
  margin: 0 auto;
  height: var(--header-height);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--space-3);
}

.logo {
  display: flex;
  flex-direction: column;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  color: var(--color-secondary-yellow);
}

.logo-topline {
  font-family: var(--font-body);
  font-size: 11px;
  line-height: var(--line-height-tight);
  color: var(--color-text-muted);
}

.logo-main {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  font-family: var(--font-heading);
  font-size: 20px;
  line-height: var(--line-height-tight);
}

.logo-main-zombie {
  color: var(--color-secondary-cyan);
  text-shadow: var(--shadow-neon-cyan);
}

.logo-main-awareness {
  color: var(--color-secondary-yellow);
  text-shadow: 0 0 16px rgba(255, 216, 87, 0.75);
}

/* Navigation */

.main-nav {
  margin-left: var(--space-3);
}

.nav-list {
  display: flex;
  align-items: center;
  gap: 24px;
  list-style: none;
  padding: 0;
  margin: 0;
}

.nav-item {
  white-space: nowrap;
}

.nav-link {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 4px 0;
  font-family: var(--font-body);
  font-weight: 600;
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  color: rgba(245, 245, 245, 0.8);
  transition: color 0.18s ease-out, text-shadow 0.18s ease-out;
}

.nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: -6px;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--color-secondary-cyan), transparent);
  opacity: 0;
  transform: scaleX(0.4);
  transform-origin: center;
  transition: opacity 0.18s ease-out, transform 0.18s ease-out;
}

.nav-link:hover {
  color: #ffffff;
  text-shadow: 0 0 10px rgba(255, 255, 255, 0.3);
}

.nav-link:hover::after,
.nav-item--highlight .nav-link::after {
  opacity: 1;
  transform: scaleX(1);
}

.nav-item--highlight .nav-link {
  color: var(--color-secondary-cyan);
  text-shadow: var(--shadow-neon-cyan);
}

/* Footer */

.site-footer {
  margin-top: var(--space-5);
  background: var(--footer-bg-gradient);
  border-top: 1px solid rgba(48, 48, 48, 0.9);
  padding-top: var(--space-4);
}

.footer-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 var(--space-3) var(--space-4);
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-4);
  justify-content: space-between;
  align-items: flex-start;
}

.footer-brand {
  flex: 1 1 260px;
}

.footer-logo {
  display: inline-flex;
  flex-wrap: wrap;
  gap: 6px;
  align-items: baseline;
  font-family: var(--font-heading);
  font-size: 18px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
}

.footer-logo-zombie {
  color: var(--color-secondary-cyan);
  text-shadow: var(--shadow-neon-cyan);
}

.footer-logo-awareness {
  color: var(--color-secondary-yellow);
  text-shadow: 0 0 12px rgba(255, 216, 87, 0.7);
}

.footer-tagline {
  margin-top: var(--space-2);
  max-width: 320px;
  font-size: var(--font-size-small);
  line-height: var(--line-height-relaxed);
  color: var(--color-text-muted);
}

.footer-links {
  flex: 2 1 360px;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-4);
  justify-content: flex-end;
}

.footer-column {
  min-width: 160px;
}

.footer-heading {
  margin: 0 0 var(--space-1);
  font-family: var(--font-body);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.18em;
  color: rgba(255, 255, 255, 0.7);
}

.footer-link-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-link-list li + li {
  margin-top: 6px;
}

.footer-link-list a {
  font-size: 14px;
  color: var(--color-text-muted);
  transition: color 0.18s ease-out, text-shadow 0.18s ease-out;
}

.footer-link-list a:hover {
  color: var(--color-secondary-cyan);
  text-shadow: var(--shadow-neon-cyan);
}

.footer-bottom {
  border-top: 1px solid rgba(48, 48, 48, 0.9);
  padding: var(--space-2) var(--space-3) var(--space-3);
  background: radial-gradient(circle at bottom right, rgba(159, 226, 42, 0.25) 0, rgba(0, 0, 0, 0.98) 55%);
}

.footer-copy {
  max-width: 1200px;
  margin: 0 auto;
  font-size: 12px;
  color: rgba(179, 179, 179, 0.9);
}

/* Responsive tweaks */

@media (max-width: 1024px) {
  .header-inner {
    padding-inline: var(--space-2);
  }

  .nav-list {
    gap: 18px;
  }

  .logo-main {
    font-size: 18px;
  }
}

@media (max-width: 768px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
    height: auto;
    padding-block: var(--space-2);
    gap: var(--space-2);
  }

  .main-nav {
    width: 100%;
  }

  .nav-list {
    overflow-x: auto;
    padding-bottom: 4px;
  }

  .footer-inner {
    padding-inline: var(--space-2);
  }

  .footer-links {
    justify-content: flex-start;
  }

  .footer-bottom {
    padding-inline: var(--space-2);
  }
}

@media (max-width: 480px) {
  .nav-list {
    gap: 14px;
  }

  .nav-link {
    font-size: 11px;
    letter-spacing: 0.14em;
  }

  .footer-logo {
    font-size: 16px;
  }
}
